30	/********************************************************************
31	 * Compare the configurable children list with a given list of fabric sub-keys
32	 * Return true if exact naming-matches are found
33	 * When searching for matching, we consider
34	 * - alias is treated as No. 1 reference
35	 * - the <name, value> pair as No. 2 reference
36	 *******************************************************************/
37	static bool submodule_memory_modules_match_fabric_key(
38	  ModuleManager& module_manager, const ModuleId& module_id,
39	  const FabricKey& fabric_key, const FabricKeyModuleId& key_module_id) {
40	  /* If the length does not match, conclusion is easy to be made */
41	  size_t len_module_memory =
42	    module_manager
43	      .configurable_children(module_id,
44	                             ModuleManager::e_config_child_type::PHYSICAL)
45	      .size();
46	  size_t len_fabric_sub_key = fabric_key.sub_keys(key_module_id).size();
47	  if (len_module_memory != len_fabric_sub_key) {
48	    return false;
49	  }
50	  /* Now walk through the child one by one */
51	  for (size_t ikey = 0; ikey < len_module_memory; ++ikey) {
52	    FabricSubKeyId key_id = fabric_key.sub_keys(key_module_id)[ikey];
53	    std::pair<ModuleId, size_t> inst_info(ModuleId::INVALID(), 0);
54	    /* Try to match the alias */
55	    if (!fabric_key.sub_key_alias(key_id).empty()) {
56	      if (!fabric_key.sub_key_name(key_id).empty()) {
57	        inst_info.first =
58	          module_manager.find_module(fabric_key.sub_key_name(key_id));
59	        inst_info.second = module_manager.instance_id(
60	          module_id, inst_info.first, fabric_key.sub_key_alias(key_id));
61	      } else {
62	        inst_info = find_module_manager_instance_module_info(
63	          module_manager, module_id, fabric_key.sub_key_alias(key_id));
64	      }
65	    } else {
66	      inst_info.first =
67	        module_manager.find_module(fabric_key.sub_key_name(key_id));
68	      inst_info.second = fabric_key.sub_key_value(key_id);
69	    }
70	    if (inst_info.first !=
71	          module_manager.configurable_children(
72	            module_id, ModuleManager::e_config_child_type::PHYSICAL)[ikey] ||
73	        inst_info.second !=
74	          module_manager.configurable_child_instances(
75	            module_id, ModuleManager::e_config_child_type::PHYSICAL)[ikey]) {
76	      return false;
77	    }
78	  }
79	  return true;
80	}
81	
82	/********************************************************************
83	 * Update the configurable children list based on fabric key definitions
84	 *******************************************************************/
85	static bool update_submodule_memory_modules_from_fabric_key(
86	  ModuleManager& module_manager, const ModuleId& module_id,
87	  const CircuitLibrary& circuit_lib, const ConfigProtocol& config_protocol,
88	  const ModuleManager::e_config_child_type& config_child_type,
89	  const FabricKey& fabric_key, const FabricKeyModuleId& key_module_id) {
90	  /* Reset the configurable children */
91	  module_manager.clear_configurable_children(module_id);
92	
93	  for (FabricSubKeyId key_id : fabric_key.sub_keys(key_module_id)) {
94	    std::pair<ModuleId, size_t> inst_info(ModuleId::INVALID(), 0);
95	    /* Try to match the alias */
96	    if (!fabric_key.sub_key_alias(key_id).empty()) {
97	      if (!fabric_key.sub_key_name(key_id).empty()) {
98	        inst_info.first =
99	          module_manager.find_module(fabric_key.sub_key_name(key_id));
100	        inst_info.second = module_manager.instance_id(
101	          module_id, inst_info.first, fabric_key.sub_key_alias(key_id));
102	      } else {
103	        inst_info = find_module_manager_instance_module_info(
104	          module_manager, module_id, fabric_key.sub_key_alias(key_id));
105	      }
106	    } else {
107	      inst_info.first =
108	        module_manager.find_module(fabric_key.sub_key_name(key_id));
109	      inst_info.second = fabric_key.sub_key_value(key_id);
110	    }
111	    if (false == module_manager.valid_module_id(inst_info.first)) {
112	      if (!fabric_key.sub_key_alias(key_id).empty()) {
113	        VTR_LOG_ERROR("Invalid key alias '%s'!\n",
114	                      fabric_key.sub_key_alias(key_id).c_str());
115	      } else {
116	        VTR_LOG_ERROR("Invalid key name '%s'!\n",
117	                      fabric_key.sub_key_name(key_id).c_str());
118	      }
119	      return CMD_EXEC_FATAL_ERROR;
120	    }
121	
122	    if (false == module_manager.valid_module_instance_id(
123	                   module_id, inst_info.first, inst_info.second)) {
124	      if (!fabric_key.sub_key_alias(key_id).empty()) {
125	        VTR_LOG_ERROR("Invalid key alias '%s'!\n",
126	                      fabric_key.sub_key_alias(key_id).c_str());
127	      } else {
128	        VTR_LOG_ERROR("Invalid key value '%ld'!\n", inst_info.second);
129	      }
130	      return CMD_EXEC_FATAL_ERROR;
131	    }
132	
133	    /* If the the child has not configuration bits, error out */
134	    if (0 == find_module_num_config_bits(
135	               module_manager, inst_info.first, circuit_lib,
136	               config_protocol.memory_model(), config_protocol.type())) {
137	      if (!fabric_key.sub_key_alias(key_id).empty()) {
138	        VTR_LOG_ERROR(
139	          "Invalid key alias '%s' which has zero configuration bits!\n",
140	          fabric_key.sub_key_alias(key_id).c_str());
141	      } else {
142	        VTR_LOG_ERROR(
143	          "Invalid key name '%s' which has zero configuration bits!\n",
144	          fabric_key.sub_key_name(key_id).c_str());
145	      }
146	      return CMD_EXEC_FATAL_ERROR;
147	    }
148	
149	    /* Now we can add the child to configurable children of the top module */
150	    module_manager.add_configurable_child(module_id, inst_info.first,
151	                                          inst_info.second, config_child_type,
152	                                          vtr::Point<int>(-1, -1));
153	  }
154	  return CMD_EXEC_SUCCESS;
155	}
