157	/********************************************************************
158	 * Remove the nets around the configuration chain (ccff_head and ccff_tails)
159	 *******************************************************************/
160	static int remove_submodule_nets_cmos_memory_chain_config_bus(
161	  ModuleManager& module_manager, const ModuleId& parent_module,
162	  const e_config_protocol_type& sram_orgz_type,
163	  const ModuleManager::e_config_child_type& config_child_type) {
164	  for (size_t mem_index = 0;
165	       mem_index <
166	       module_manager.configurable_children(parent_module, config_child_type)
167	         .size();
168	       ++mem_index) {
169	    ModuleId net_src_module_id;
170	    size_t net_src_instance_id;
171	    ModulePortId net_src_port_id;
172	
173	    if (0 == mem_index) {
174	      /* Find the port name of configuration chain head */
175	      std::string src_port_name =
176	        generate_sram_port_name(sram_orgz_type, CIRCUIT_MODEL_PORT_INPUT);
177	      net_src_module_id = parent_module;
178	      net_src_instance_id = 0;
179	      net_src_port_id =
180	        module_manager.find_module_port(net_src_module_id, src_port_name);
181	    } else {
182	      /* Find the port name of previous memory module */
183	      std::string src_port_name = generate_configuration_chain_tail_name();
184	      net_src_module_id = module_manager.configurable_children(
185	        parent_module, config_child_type)[mem_index - 1];
186	      net_src_instance_id = module_manager.configurable_child_instances(
187	        parent_module, config_child_type)[mem_index - 1];
188	      net_src_port_id =
189	        module_manager.find_module_port(net_src_module_id, src_port_name);
190	    }
191	
192	    /* Get the pin id for source port */
193	    BasicPort net_src_port =
194	      module_manager.module_port(net_src_module_id, net_src_port_id);
195	
196	    /* Create a net for each pin */
197	    for (size_t pin_id = 0; pin_id < net_src_port.pins().size(); ++pin_id) {
198	      /* Find the net from which the source node is driving */
199	      ModuleNetId net = module_manager.module_instance_port_net(
200	        parent_module, net_src_module_id, net_src_instance_id, net_src_port_id,
201	        net_src_port.pins()[pin_id]);
202	      /* Remove the net including sources and sinks */
203	      module_manager.clear_module_net_sinks(parent_module, net);
204	    }
205	  }
206	
207	  /* For the last memory module:
208	   *    net source is the configuration chain tail of the previous memory module
209	   *    net sink is the configuration chain tail of the primitive module
210	   */
211	  /* Find the port name of previous memory module */
212	  std::string src_port_name = generate_configuration_chain_tail_name();
213	  ModuleId net_src_module_id =
214	    module_manager.configurable_children(parent_module, config_child_type)
215	      .back();
216	  size_t net_src_instance_id =
217	    module_manager
218	      .configurable_child_instances(parent_module, config_child_type)
219	      .back();
220	  ModulePortId net_src_port_id =
221	    module_manager.find_module_port(net_src_module_id, src_port_name);
222	
223	  /* Get the pin id for source port */
224	  BasicPort net_src_port =
225	    module_manager.module_port(net_src_module_id, net_src_port_id);
226	
227	  /* Create a net for each pin */
228	  for (size_t pin_id = 0; pin_id < net_src_port.pins().size(); ++pin_id) {
229	    /* Find the net from which the source node is driving */
230	    ModuleNetId net = module_manager.module_instance_port_net(
231	      parent_module, net_src_module_id, net_src_instance_id, net_src_port_id,
232	      net_src_port.pins()[pin_id]);
233	    /* Remove the net including sources and sinks */
234	    module_manager.clear_module_net_sinks(parent_module, net);
235	  }
236	  return CMD_EXEC_SUCCESS;
237	}
