507	/********************************************************************
508	 * Load and update the configurable children of a given module (not a top-level
509	 *module) Compare the configurable children list with fabric sub-keys.
510	 * - If match, nothing should be done
511	 * - If not match,
512	 *   - remove the nets related to configurable children
513	 *   - rebuild the configurable children list
514	 *   - add the nets related to configurable children
515	 *******************************************************************/
516	static int load_and_update_submodule_memory_modules_from_fabric_key(
517	  ModuleManager& module_manager, const ModuleId& module_id,
518	  const CircuitLibrary& circuit_lib, const ConfigProtocol& config_protocol,
519	  const FabricKey& fabric_key, const FabricKeyModuleId& key_module_id,
520	  const bool& group_config_block) {
521	  int status = CMD_EXEC_SUCCESS;
522	  /* Compare the configurable children list */
523	  if (submodule_memory_modules_match_fabric_key(module_manager, module_id,
524	                                                fabric_key, key_module_id)) {
525	    return CMD_EXEC_SUCCESS;
526	  }
527	  /* Do not match, now remove all the nets for the configurable children */
528	  status = remove_submodule_configurable_children_nets(
529	    module_manager, module_id, circuit_lib, config_protocol,
530	    ModuleManager::e_config_child_type::PHYSICAL);
531	  if (status == CMD_EXEC_FATAL_ERROR) {
532	    return status;
533	  }
534	  /* Overwrite the configurable children list */
535	  status = update_submodule_memory_modules_from_fabric_key(
536	    module_manager, module_id, circuit_lib, config_protocol,
537	    group_config_block ? ModuleManager::e_config_child_type::PHYSICAL
538	                       : ModuleManager::e_config_child_type::UNIFIED,
539	    fabric_key, key_module_id);
540	  if (status == CMD_EXEC_FATAL_ERROR) {
541	    return status;
542	  }
543	  /* TODO: Create the nets for the new list of configurable children */
544	  status = rebuild_submodule_configurable_children_nets(
545	    module_manager, module_id, circuit_lib, config_protocol,
546	    ModuleManager::e_config_child_type::PHYSICAL);
547	  if (status == CMD_EXEC_FATAL_ERROR) {
548	    return status;
549	  }
550	  return status;
551	}
552	
553	/********************************************************************
554	 * Load and update the configurable children of a given list of modules (not a
555	 *top-level module)
556	 *******************************************************************/
557	int load_submodules_memory_modules_from_fabric_key(
558	  ModuleManager& module_manager, const CircuitLibrary& circuit_lib,
559	  const ConfigProtocol& config_protocol, const FabricKey& fabric_key,
560	  const bool& group_config_block) {
561	  int status = CMD_EXEC_SUCCESS;
562	  for (FabricKeyModuleId key_module_id : fabric_key.modules()) {
563	    std::string module_name = fabric_key.module_name(key_module_id);
564	    /* Ensure this is not a top module! */
565	    if (module_name == std::string(FPGA_TOP_MODULE_NAME)) {
566	      VTR_LOG_ERROR(
567	        "Expect a non-top-level name for the sub-module '%s' in fabric key!\n",
568	        module_name.c_str());
569	      return CMD_EXEC_FATAL_ERROR;
570	    }
571	    ModuleId module_id = module_manager.find_module(module_name);
572	    if (module_id) {
573	      /* This is a valid module, try to load and update */
574	      status = load_and_update_submodule_memory_modules_from_fabric_key(
575	        module_manager, module_id, circuit_lib, config_protocol, fabric_key,
576	        key_module_id, group_config_block);
577	      if (status == CMD_EXEC_FATAL_ERROR) {
578	        return status;
579	      }
580	    } else {
581	      /* Not a valid module, report error */
582	      VTR_LOG_ERROR(
583	        "The sub-module '%s' in fabric key is not a valid module in FPGA "
584	        "fabric!\n",
585	        module_name.c_str());
586	      return CMD_EXEC_FATAL_ERROR;
587	    }
588	  }
589	  return status;
590	}
591	
592	} /* end namespace openfpga */
