/*********************************************************************
 * This function to add nets for quicklogic memory banks using shift registers
 *to manipulate BL/WLs Each configuration region has independent BL/WL shift
 *register banks
 * - Find the number of BLs and WLs required for each region
 * - Find the number of BL and WL shift register chains required for each region
 * - Create the module of shift register chain for each unique size
 * - Create nets to connect from top-level module inputs to BL/WL shift register
 *chains
 * - Create nets to connect from BL/WL shift register chains to BL/WL of
 *configurable children
 *
 * @note this function only adds the BL protocol
 *
 * Detailed schematic of each memory bank:
 * @note The numbers are just made to show a simplified example, practical cases
 *are more complicated!
 *
 *                                  sr_clk               sr_head     sr_tail
 *                                    |                   |             ^
 *                                    v                   v             |
 *                           +-------------------------------------------------+
 *                           |         Bit Line shift register chains          |
 *                           +-------------------------------------------------+
 *                               |              |                    |
 *    +---------+              BL[0:9]        BL[10:17]          BL[18:22]
 *    |         |                |              |                    |
 *    |         |                |              |                    |
 *    | Word    |--WL[0:3]-->-----------+---------------+----  ...   |------+-->
 *    |         |                |      |       |       |            |      |
 *    | Line    |                |      v       |       v            |      v
 *    |         |                |   +-------+  |   +-------+        |  +------+
 *    | shift   |                +-->| SRAM  |  +-->| SRAM  |        +->| SRAM |
 *    |         |                |   | [0:8] |  |   | [0:5] |   ...  |  | [0:7]|
 *    | register|                |   +-------+  |   +-------+        |  +------+
 *    |         |                |              |                    |
 *    | chains  |--WL[4:14]  -----------+--------------+---------    | -----+-->
 *    |         |                |      |       |       |            |      |
 *    |         |                |      v       |       v            |      v
 *    |         |                |   +-------+  |   +-------+        | +-------+
 *    |         |                +-->| SRAM  |  |   | SRAM  |        +->| SRAM |
 *    |         |                |   | [0:80]|  |   | [0:63]|   ...  |  |
 *[0:31]| |         |                |   +-------+  |   +-------+        |
 *+-------+ |         |                |                                   | |
 *|                |     ...     ...    ...            |    ... |         | | |
 *| |         |--WL[15:18] -----------+---------------+----  ---   | -----+-->
 *    |         |                |      |       |       |            |      |
 *    |         |                |      v       |       v            |      v
 *    +---------+                |   +-------+  |   +-------+        | +-------+
 *                               +-->| SRAM  |  +-->| SRAM  |        +->| SRAM |
 *                               |   |[0:5]  |  |   | [0:8] |   ...  |  | [0:2]
 *| |   +-------+  |   +-------+        |  +-------+ v              v v WL[0:9]
 *WL[0:7]                WL[0:4]
 *
 **********************************************************************/
static void
add_top_module_nets_cmos_ql_memory_bank_bl_shift_register_config_bus(
  ModuleManager& module_manager, MemoryBankShiftRegisterBanks& sr_banks,
  const ModuleId& top_module, const CircuitLibrary& circuit_lib,
  const ConfigProtocol& config_protocol) {
  CircuitModelId sram_model = config_protocol.memory_model();
  CircuitModelId bl_memory_model = config_protocol.bl_memory_model();
  /* Find out the unique shift register chain sizes */
  std::vector<size_t> unique_sr_sizes = sr_banks.bl_bank_unique_sizes();

  /* Build submodules for shift register chains */
  for (const size_t& sr_size : unique_sr_sizes) {
    std::string sr_module_name = generate_bl_shift_register_module_name(
      circuit_lib.model_name(bl_memory_model), sr_size);
    build_bl_shift_register_chain_module(
      module_manager, circuit_lib, sr_module_name, bl_memory_model, sr_size);
  }

  /* Instanciate the shift register chains in the top-level module */
  for (const ConfigRegionId& config_region :
       module_manager.regions(top_module)) {
    for (const FabricBitLineBankId& sr_bank :
         sr_banks.bl_banks(config_region)) {
      size_t bl_bank_size = sr_banks.bl_bank_size(config_region, sr_bank);
      std::string sr_module_name = generate_bl_shift_register_module_name(
        circuit_lib.model_name(bl_memory_model), bl_bank_size);
      ModuleId sr_bank_module = module_manager.find_module(sr_module_name);
      VTR_ASSERT(sr_bank_module);

      size_t cur_inst = module_manager.num_instance(top_module, sr_bank_module);
      module_manager.add_child_module(top_module, sr_bank_module, false);

      sr_banks.link_bl_shift_register_bank_to_module(config_region, sr_bank,
                                                     sr_bank_module);
      sr_banks.link_bl_shift_register_bank_to_instance(config_region, sr_bank,
                                                       cur_inst);
    }
  }

  for (const ConfigRegionId& config_region :
       module_manager.regions(top_module)) {
    /**************************************************************
     * Precompute the BLs and WLs distribution across the FPGA fabric
     * The distribution is a matrix which contains the starting index of BL/WL
     * for each column or row
     */
    std::pair<int, int> child_x_range =
      compute_memory_bank_regional_configurable_child_x_range(
        module_manager, top_module, config_region);
    std::map<int, size_t> num_bls_per_tile =
      compute_memory_bank_regional_bitline_numbers_per_tile(
        module_manager, top_module, config_region, circuit_lib, sram_model);
    std::map<int, size_t> bl_start_index_per_tile =
      compute_memory_bank_regional_blwl_start_index_per_tile(child_x_range,
                                                             num_bls_per_tile);

    for (size_t child_id = 0;
         child_id <
         module_manager.region_configurable_children(top_module, config_region)
           .size();
         ++child_id) {
      ModuleId child_module = module_manager.region_configurable_children(
        top_module, config_region)[child_id];
      vtr::Point<int> coord =
        module_manager.region_configurable_child_coordinates(
          top_module, config_region)[child_id];

      /* Find the BL port */
      ModulePortId child_bl_port = module_manager.find_module_port(
        child_module, std::string(MEMORY_BL_PORT_NAME));
      BasicPort child_bl_port_info =
        module_manager.module_port(child_module, child_bl_port);

      size_t cur_bl_index = 0;

      for (const size_t& sink_bl_pin : child_bl_port_info.pins()) {
        /* Find the shift register bank id for the driving BL port */
        size_t bl_pin_id = bl_start_index_per_tile[coord.x()] + cur_bl_index;
        BasicPort src_bl_port(std::string(MEMORY_BL_PORT_NAME), bl_pin_id,
                              bl_pin_id);
        FabricBitLineBankId sr_bank =
          sr_banks.find_bl_shift_register_bank_id(config_region, src_bl_port);
        BasicPort sr_bank_port = sr_banks.find_bl_shift_register_bank_data_port(
          config_region, src_bl_port);
        VTR_ASSERT(sr_bank_port.is_valid());

        sr_banks.add_bl_shift_register_bank_sink_node(
          config_region, sr_bank, sr_bank_port, child_id, sink_bl_pin);

        cur_bl_index++;
      }
    }
  }

  /* Create connections between top-level module and the BL shift register banks
   * - Connect the head port from top-level module to each shift register bank
   * - Connect the tail port from each shift register bank to top-level module
   */
  add_top_module_nets_cmos_ql_memory_bank_bl_shift_register_bank_heads(
    module_manager, top_module, sr_banks);

  add_top_module_nets_cmos_ql_memory_bank_bl_shift_register_bank_tails(
    module_manager, top_module, sr_banks);

  /* Create connections between BLs of top-level module and BLs of child modules
   * for each region */
  add_top_module_nets_cmos_ql_memory_bank_bl_shift_register_bank_bls(
    module_manager, top_module, sr_banks,
    std::string(BL_SHIFT_REGISTER_CHAIN_BL_OUT_NAME),
    std::string(MEMORY_BL_PORT_NAME));
}

/*********************************************************************
 * Top-level function to add nets for quicklogic memory banks using shift
 *registers to control BL/WLs
 *
 * @note this function only adds the WL configuration bus
 *
 * @note see detailed explanation on the bus connection in function
 *add_top_module_nets_cmos_ql_memory_bank_bl_shift_register_config_bus()
 **********************************************************************/
static void
add_top_module_nets_cmos_ql_memory_bank_wl_shift_register_config_bus(
  ModuleManager& module_manager, MemoryBankShiftRegisterBanks& sr_banks,
  const ModuleId& top_module, const CircuitLibrary& circuit_lib,
  const ConfigProtocol& config_protocol) {
  CircuitModelId sram_model = config_protocol.memory_model();
  CircuitModelId wl_memory_model = config_protocol.wl_memory_model();
  /* Find out the unique shift register chain sizes */
  std::vector<size_t> unique_sr_sizes = sr_banks.wl_bank_unique_sizes();

  /* Build submodules for shift register chains */
  for (const size_t& sr_size : unique_sr_sizes) {
    std::string sr_module_name = generate_wl_shift_register_module_name(
      circuit_lib.model_name(wl_memory_model), sr_size);
    build_wl_shift_register_chain_module(
      module_manager, circuit_lib, sr_module_name, wl_memory_model, sr_size);
  }

  /* Instanciate the shift register chains in the top-level module */
  for (const ConfigRegionId& config_region :
       module_manager.regions(top_module)) {
    for (const FabricWordLineBankId& sr_bank :
         sr_banks.wl_banks(config_region)) {
      size_t wl_bank_size = sr_banks.wl_bank_size(config_region, sr_bank);
      std::string sr_module_name = generate_wl_shift_register_module_name(
        circuit_lib.model_name(wl_memory_model), wl_bank_size);
      ModuleId sr_bank_module = module_manager.find_module(sr_module_name);
      VTR_ASSERT(sr_bank_module);

      size_t cur_inst = module_manager.num_instance(top_module, sr_bank_module);
      module_manager.add_child_module(top_module, sr_bank_module, false);

      sr_banks.link_wl_shift_register_bank_to_module(config_region, sr_bank,
                                                     sr_bank_module);
      sr_banks.link_wl_shift_register_bank_to_instance(config_region, sr_bank,
                                                       cur_inst);
    }
  }

  for (const ConfigRegionId& config_region :
       module_manager.regions(top_module)) {
    /**************************************************************
     * Precompute the BLs and WLs distribution across the FPGA fabric
     * The distribution is a matrix which contains the starting index of BL/WL
     * for each column or row
     */
    std::pair<int, int> child_y_range =
      compute_memory_bank_regional_configurable_child_y_range(
        module_manager, top_module, config_region);
    std::map<int, size_t> num_wls_per_tile =
      compute_memory_bank_regional_wordline_numbers_per_tile(
        module_manager, top_module, config_region, circuit_lib, sram_model);
    std::map<int, size_t> wl_start_index_per_tile =
      compute_memory_bank_regional_blwl_start_index_per_tile(child_y_range,
                                                             num_wls_per_tile);

    for (size_t child_id = 0;
         child_id <
         module_manager.region_configurable_children(top_module, config_region)
           .size();
         ++child_id) {
      ModuleId child_module = module_manager.region_configurable_children(
        top_module, config_region)[child_id];
      vtr::Point<int> coord =
        module_manager.region_configurable_child_coordinates(
          top_module, config_region)[child_id];

      size_t cur_wl_index = 0;

      /* Find the WL port */
      ModulePortId child_wl_port = module_manager.find_module_port(
        child_module, std::string(MEMORY_WL_PORT_NAME));
      BasicPort child_wl_port_info =
        module_manager.module_port(child_module, child_wl_port);

      for (const size_t& sink_wl_pin : child_wl_port_info.pins()) {
        size_t wl_pin_id = wl_start_index_per_tile[coord.y()] + cur_wl_index;
        BasicPort src_wl_port(std::string(MEMORY_WL_PORT_NAME), wl_pin_id,
                              wl_pin_id);

        FabricWordLineBankId sr_bank =
          sr_banks.find_wl_shift_register_bank_id(config_region, src_wl_port);
        BasicPort sr_bank_port = sr_banks.find_wl_shift_register_bank_data_port(
          config_region, src_wl_port);
        VTR_ASSERT(sr_bank_port.is_valid());

        sr_banks.add_wl_shift_register_bank_sink_node(
          config_region, sr_bank, sr_bank_port, child_id, sink_wl_pin);

        cur_wl_index++;
      }
    }
  }

  /* Create connections between top-level module and the BL shift register banks
   * - Connect the head port from top-level module to each shift register bank
   * - Connect the tail port from each shift register bank to top-level module
   */
  add_top_module_nets_cmos_ql_memory_bank_wl_shift_register_bank_heads(
    module_manager, top_module, sr_banks);

  add_top_module_nets_cmos_ql_memory_bank_wl_shift_register_bank_tails(
    module_manager, top_module, sr_banks);

  /* Create connections between BLs of top-level module and BLs of child modules
   * for each region */
  add_top_module_nets_cmos_ql_memory_bank_wl_shift_register_bank_wls(
    module_manager, top_module, sr_banks,
    std::string(WL_SHIFT_REGISTER_CHAIN_WL_OUT_NAME),
    std::string(MEMORY_WL_PORT_NAME));
  add_top_module_nets_cmos_ql_memory_bank_wl_shift_register_bank_wls(
    module_manager, top_module, sr_banks,
    std::string(WL_SHIFT_REGISTER_CHAIN_WLR_OUT_NAME),
    std::string(MEMORY_WLR_PORT_NAME), true);
}

/*********************************************************************
 * Top-level function to add nets for quicklogic memory banks
 * - Each configuration region has independent memory bank circuitry
 * - BL and WL may have different circuitry and wire connection, e.g., decoder,
 *flatten or shift-registers
 * - BL control circuitry
 *   - Decoder: Add a BL decoder; Connect enable, address and data-in (din)
 *between top-level and decoders; Connect data ports between between the decoder
 *and configurable child modules
 *   - Flatten: Connect BLs between the top-level port and configurable child
 *modules
 *   - TODO: Shift registers: add blocks of shift register chain (could be
 *multi-head); Connect shift register outputs to configurable child modules
 *
 * - WL control circuitry
 *   - Decoder: Add a WL decoder; Connect address ports between top-level and
 *decoders; Connect data ports between the decoder and configurable child
 *modules
 *   - Flatten: Connect BLs between the top-level port and configurable child
 *modules
 *   - TODO: Shift registers: add blocks of shift register chain (could be
 *multi-head); Connect shift register outputs to configurable child modules
 ********************************************************************/
void add_top_module_nets_cmos_ql_memory_bank_config_bus(
  ModuleManager& module_manager, DecoderLibrary& decoder_lib,
  MemoryBankShiftRegisterBanks& blwl_sr_banks, const ModuleId& top_module,
  const CircuitLibrary& circuit_lib, const ConfigProtocol& config_protocol,
  const TopModuleNumConfigBits& num_config_bits) {
  VTR_ASSERT_SAFE(CONFIG_MEM_QL_MEMORY_BANK == config_protocol.type());
  CircuitModelId sram_model = config_protocol.memory_model();

  switch (config_protocol.bl_protocol_type()) {
    case BLWL_PROTOCOL_DECODER: {
      add_top_module_nets_cmos_ql_memory_bank_bl_decoder_config_bus(
        module_manager, decoder_lib, top_module, circuit_lib, sram_model,
        num_config_bits);
      break;
    }
    case BLWL_PROTOCOL_FLATTEN: {
      add_top_module_nets_cmos_ql_memory_bank_bl_flatten_config_bus(
        module_manager, top_module, circuit_lib, sram_model);
      break;
    }
    case BLWL_PROTOCOL_SHIFT_REGISTER: {
      add_top_module_nets_cmos_ql_memory_bank_bl_shift_register_config_bus(
        module_manager, blwl_sr_banks, top_module, circuit_lib,
        config_protocol);
      break;
    }
    default: {
      VTR_LOG_ERROR("Invalid BL protocol");
      exit(1);
    }
  }

  switch (config_protocol.wl_protocol_type()) {
    case BLWL_PROTOCOL_DECODER: {
      add_top_module_nets_cmos_ql_memory_bank_wl_decoder_config_bus(
        module_manager, decoder_lib, top_module, circuit_lib, sram_model,
        num_config_bits);
      break;
    }
    case BLWL_PROTOCOL_FLATTEN: {
      add_top_module_nets_cmos_ql_memory_bank_wl_flatten_config_bus(
        module_manager, top_module, circuit_lib, sram_model);
      break;
    }
    case BLWL_PROTOCOL_SHIFT_REGISTER: {
      add_top_module_nets_cmos_ql_memory_bank_wl_shift_register_config_bus(
        module_manager, blwl_sr_banks, top_module, circuit_lib,
        config_protocol);
      break;
    }
    default: {
      VTR_LOG_ERROR("Invalid WL protocol");
      exit(1);
    }
  }
}

/********************************************************************
 * Add a list of ports that are used for SRAM configuration to the FPGA
 * top-level module
 * - Add ports for BL control circuitry:
 *   - Decoder
 *     - an enable signals
 *     - an BL address port
 *     - a data-in port
 *   - Flatten
 *     - BL ports
 *   - TODO: Shift registers
 *     - Head of shift register chain for BLs
 *     - Tail of shift register chain for BLs
 *
 * - Add ports for WL control circuitry:
 *   - Decoder
 *     - an WL address port
 *     - a Readback port (Optional, only needed when WLR is required)
 *   - Flatten
 *     - WL ports
 *     - WLR ports (Optional)
 *   - TODO: Shift registers
 *     - Head of shift register chain for WLs
 *     - Tail of shift register chain for WLs
 *     - a Readback port (Optional, only needed when WLR is required)
 *
 * @note In this memory decoders, the address size will be computed in a
 *different way than the regular one
 ********************************************************************/
void add_top_module_ql_memory_bank_sram_ports(
  ModuleManager& module_manager, const ModuleId& module_id,
  const CircuitLibrary& circuit_lib, const ConfigProtocol& config_protocol,
  const MemoryBankShiftRegisterBanks& blwl_sr_banks,
  const TopModuleNumConfigBits& num_config_bits) {
  VTR_ASSERT_SAFE(CONFIG_MEM_QL_MEMORY_BANK == config_protocol.type());
  CircuitModelId sram_model = config_protocol.memory_model();

  switch (config_protocol.bl_protocol_type()) {
    case BLWL_PROTOCOL_DECODER: {
      /* Add enable signals */
      BasicPort en_port(std::string(DECODER_ENABLE_PORT_NAME), 1);
      module_manager.add_port(module_id, en_port,
                              ModuleManager::MODULE_INPUT_PORT);

      /* BL address size is the largest among all the regions */
      size_t bl_addr_size = 0;
      for (const ConfigRegionId& config_region :
           module_manager.regions(module_id)) {
        bl_addr_size =
          std::max(bl_addr_size, find_mux_local_decoder_addr_size(
                                   num_config_bits[config_region].first));
      }
      BasicPort bl_addr_port(std::string(DECODER_BL_ADDRESS_PORT_NAME),
                             bl_addr_size);
      module_manager.add_port(module_id, bl_addr_port,
                              ModuleManager::MODULE_INPUT_PORT);

      /* Data input should be dependent on the number of configuration regions*/
      BasicPort din_port(std::string(DECODER_DATA_IN_PORT_NAME),
                         config_protocol.num_regions());
      module_manager.add_port(module_id, din_port,
                              ModuleManager::MODULE_INPUT_PORT);
      break;
    }
    case BLWL_PROTOCOL_FLATTEN: {
      /* Each region will have independent BLs */
      for (const ConfigRegionId& config_region :
           module_manager.regions(module_id)) {
        size_t bl_size = num_config_bits[config_region].first;
        BasicPort bl_port(generate_regional_blwl_port_name(
                            std::string(MEMORY_BL_PORT_NAME), config_region),
                          bl_size);
        module_manager.add_port(module_id, bl_port,
                                ModuleManager::MODULE_INPUT_PORT);
      }
      break;
    }
    case BLWL_PROTOCOL_SHIFT_REGISTER: {
      /* Each region will have independent shift register banks */
      for (const ConfigRegionId& config_region :
           module_manager.regions(module_id)) {
        size_t num_heads = blwl_sr_banks.bl_banks(config_region).size();
        BasicPort blsr_head_port(
          generate_regional_blwl_port_name(
            std::string(BL_SHIFT_REGISTER_CHAIN_HEAD_NAME), config_region),
          num_heads);
        module_manager.add_port(module_id, blsr_head_port,
                                ModuleManager::MODULE_INPUT_PORT);
        BasicPort blsr_tail_port(
          generate_regional_blwl_port_name(
            std::string(BL_SHIFT_REGISTER_CHAIN_TAIL_NAME), config_region),
          num_heads);
        module_manager.add_port(module_id, blsr_tail_port,
                                ModuleManager::MODULE_OUTPUT_PORT);
      }
      break;
    }
    default: {
      VTR_LOG_ERROR("Invalid BL protocol");
      exit(1);
    }
  }

  switch (config_protocol.wl_protocol_type()) {
    case BLWL_PROTOCOL_DECODER: {
      /* WL address size is the largest among all the regions */
      size_t wl_addr_size = 0;
      for (const ConfigRegionId& config_region :
           module_manager.regions(module_id)) {
        wl_addr_size =
          std::max(wl_addr_size, find_mux_local_decoder_addr_size(
                                   num_config_bits[config_region].second));
      }
      BasicPort wl_addr_port(std::string(DECODER_WL_ADDRESS_PORT_NAME),
                             wl_addr_size);
      module_manager.add_port(module_id, wl_addr_port,
                              ModuleManager::MODULE_INPUT_PORT);

      /* Optional: If we have WLR port, we should add a read-back port */
      if (!circuit_lib.model_ports_by_type(sram_model, CIRCUIT_MODEL_PORT_WLR)
             .empty()) {
        BasicPort readback_port(std::string(DECODER_READBACK_PORT_NAME),
                                config_protocol.num_regions());
        module_manager.add_port(module_id, readback_port,
                                ModuleManager::MODULE_INPUT_PORT);
      }
      break;
    }
    case BLWL_PROTOCOL_FLATTEN: {
      /* Each region will have independent WLs */
      for (const ConfigRegionId& config_region :
           module_manager.regions(module_id)) {
        size_t wl_size = num_config_bits[config_region].second;
        BasicPort wl_port(generate_regional_blwl_port_name(
                            std::string(MEMORY_WL_PORT_NAME), config_region),
                          wl_size);
        module_manager.add_port(module_id, wl_port,
                                ModuleManager::MODULE_INPUT_PORT);

        /* Optional: If we have WLR port, we should add a read-back port */
        if (!circuit_lib.model_ports_by_type(sram_model, CIRCUIT_MODEL_PORT_WLR)
               .empty()) {
          BasicPort wlr_port(
            generate_regional_blwl_port_name(std::string(MEMORY_WLR_PORT_NAME),
                                             config_region),
            wl_size);
          module_manager.add_port(module_id, wlr_port,
                                  ModuleManager::MODULE_INPUT_PORT);
        }
      }
      break;
    }
    case BLWL_PROTOCOL_SHIFT_REGISTER: {
      /* Each region will have independent shift register banks */
      for (const ConfigRegionId& config_region :
           module_manager.regions(module_id)) {
        size_t num_heads = blwl_sr_banks.wl_banks(config_region).size();
        BasicPort wlsr_head_port(
          generate_regional_blwl_port_name(
            std::string(WL_SHIFT_REGISTER_CHAIN_HEAD_NAME), config_region),
          num_heads);
        module_manager.add_port(module_id, wlsr_head_port,
                                ModuleManager::MODULE_INPUT_PORT);
        BasicPort wlsr_tail_port(
          generate_regional_blwl_port_name(
            std::string(WL_SHIFT_REGISTER_CHAIN_TAIL_NAME), config_region),
          num_heads);
        module_manager.add_port(module_id, wlsr_tail_port,
                                ModuleManager::MODULE_OUTPUT_PORT);
      }
      break;
    }
    default: {
      VTR_LOG_ERROR("Invalid WL protocol");
      exit(1);
    }
  }
}

/********************************************************************
 * Load the shift register bank -related data from fabric key to
 * the dedicated and unified data structure
 ********************************************************************/
int load_top_module_shift_register_banks_from_fabric_key(
  const FabricKey& fabric_key, MemoryBankShiftRegisterBanks& blwl_sr_banks) {
  blwl_sr_banks.resize_regions(fabric_key.regions().size());

  /* Load Bit-Line shift register banks */
  for (const auto& region : fabric_key.regions()) {
    blwl_sr_banks.reserve_bl_shift_register_banks(
      region, fabric_key.bl_banks(region).size());
    for (const auto& bank : fabric_key.bl_banks(region)) {
      FabricBitLineBankId sr_bank =
        blwl_sr_banks.create_bl_shift_register_bank(region);
      for (const auto& data_port :
           fabric_key.bl_bank_data_ports(region, bank)) {
        blwl_sr_banks.add_data_port_to_bl_shift_register_bank(region, sr_bank,
                                                              data_port);
      }
    }
  }

  /* Load Bit-Line shift register banks */
  for (const auto& region : fabric_key.regions()) {
    blwl_sr_banks.reserve_wl_shift_register_banks(
      region, fabric_key.wl_banks(region).size());
    for (const auto& bank : fabric_key.wl_banks(region)) {
      FabricWordLineBankId sr_bank =
        blwl_sr_banks.create_wl_shift_register_bank(region);
      for (const auto& data_port :
           fabric_key.wl_bank_data_ports(region, bank)) {
        blwl_sr_banks.add_data_port_to_wl_shift_register_bank(region, sr_bank,
                                                              data_port);
      }
    }
  }

  return 0;
}

/********************************************************************
 * @brief This functions synchronize the settings in configuration protocol
 *(from architecture description) and the existing information (loaded from
 *fabric key files)
 * @note This function should be called AFTER
 *load_top_module_shift_register_banks_from_fabric_key()
 ********************************************************************/
void sync_memory_bank_shift_register_banks_with_config_protocol_settings(
  ModuleManager& module_manager, MemoryBankShiftRegisterBanks& blwl_sr_banks,
  const ConfigProtocol& config_protocol, const ModuleId& top_module,
  const CircuitLibrary& circuit_lib) {
  /* ONLY synchronize when the configuration protocol is memory bank using shift
   * registers */
  if (CONFIG_MEM_QL_MEMORY_BANK != config_protocol.type() ||
      BLWL_PROTOCOL_SHIFT_REGISTER != config_protocol.bl_protocol_type() ||
      BLWL_PROTOCOL_SHIFT_REGISTER != config_protocol.wl_protocol_type()) {
    return;
  }

  /* Fabric key has a higher priority in defining the shift register bank
   * organization */
  if (!blwl_sr_banks.empty()) {
    return;
  }

  CircuitModelId sram_model = config_protocol.memory_model();

  /* Reach here, if means we do not have any definition from fabric key files,
   * use the settings from the configuration protocol */
  blwl_sr_banks.resize_regions(module_manager.regions(top_module).size());

  /* Based on the number of shift register banks, evenly distribute the BLs in
   * each region for each shift register bank */
  for (const auto& config_region : module_manager.regions(top_module)) {
    size_t num_bls = compute_memory_bank_regional_num_bls(
      module_manager, top_module, config_region, circuit_lib, sram_model);
    size_t num_bl_banks = config_protocol.bl_num_banks();
    blwl_sr_banks.reserve_bl_shift_register_banks(config_region, num_bl_banks);

    size_t regular_sr_bank_size = num_bls / num_bl_banks;
    size_t cur_bl_index = 0;
    for (size_t ibank = 0; ibank < num_bl_banks; ++ibank) {
      /* For last bank, use all the residual sizes */
      size_t cur_sr_bank_size = regular_sr_bank_size;
      if (ibank == num_bl_banks - 1) {
        cur_sr_bank_size = num_bls - ibank * regular_sr_bank_size;
      }
      /* Create a bank and assign data ports */
      FabricBitLineBankId bank =
        blwl_sr_banks.create_bl_shift_register_bank(config_region);
      BasicPort data_ports(std::string(MEMORY_BL_PORT_NAME), cur_bl_index,
                           cur_bl_index + cur_sr_bank_size - 1);
      blwl_sr_banks.add_data_port_to_bl_shift_register_bank(config_region, bank,
                                                            data_ports);

      /* Increment the bl index */
      cur_bl_index += cur_sr_bank_size;
    }

    VTR_ASSERT(cur_bl_index == num_bls);
  }

  /* Based on the number of shift register banks, evenly distribute the WLs in
   * each region for each shift register bank */
  for (const auto& config_region : module_manager.regions(top_module)) {
    size_t num_wls = compute_memory_bank_regional_num_wls(
      module_manager, top_module, config_region, circuit_lib, sram_model);
    size_t num_wl_banks = config_protocol.wl_num_banks();
    blwl_sr_banks.reserve_wl_shift_register_banks(config_region, num_wl_banks);

    size_t regular_sr_bank_size = num_wls / num_wl_banks;
    size_t cur_wl_index = 0;
    for (size_t ibank = 0; ibank < num_wl_banks; ++ibank) {
      /* For last bank, use all the residual sizes */
      size_t cur_sr_bank_size = regular_sr_bank_size;
      if (ibank == num_wl_banks - 1) {
        cur_sr_bank_size = num_wls - ibank * regular_sr_bank_size;
      }
      /* Create a bank and assign data ports */
      FabricWordLineBankId bank =
        blwl_sr_banks.create_wl_shift_register_bank(config_region);
      BasicPort data_ports(std::string(MEMORY_WL_PORT_NAME), cur_wl_index,
                           cur_wl_index + cur_sr_bank_size - 1);
      blwl_sr_banks.add_data_port_to_wl_shift_register_bank(config_region, bank,
                                                            data_ports);

      /* Increment the bl index */
      cur_wl_index += cur_sr_bank_size;
    }

    VTR_ASSERT(cur_wl_index == num_wls);
  }
}

} /* end namespace openfpga */

